# test_zip_dicts.py

import pytest

# Replace `your_module` with the actual module name where zip_dicts is defined.
from your_module import zip_dicts


def test_zip_dicts_happy_path_same_keys():
    result = zip_dicts(
        {"a": 1, "b": 2},
        {"a": 3, "b": 4},
    )

    assert result == {
        "a": [1, 3],
        "b": [2, 4],
    }


def test_zip_dicts_happy_path_different_keys():
    result = zip_dicts(
        {"a": 1, "b": 2},
        {"b": 3, "c": 4},
        {"a": 5, "c": 6},
    )

    assert result == {
        "a": [1, None, 5],
        "b": [2, 3, None],
        "c": [None, 4, 6],
    }


def test_zip_dicts_single_dict():
    result = zip_dicts({"a": 1, "b": 2})

    assert result == {
        "a": [1],
        "b": [2],
    }


def test_zip_dicts_no_dicts():
    assert zip_dicts() == {}


def test_zip_dicts_with_empty_dicts():
    result = zip_dicts(
        {},
        {"a": 1},
        {},
    )

    assert result == {
        "a": [None, 1, None],
    }


def test_zip_dicts_all_empty_dicts():
    assert zip_dicts({}, {}, {}) == {}


def test_zip_dicts_preserves_none_values():
    result = zip_dicts(
        {"a": None},
        {"a": 1},
        {},
    )

    assert result == {
        "a": [None, 1, None],
    }


def test_zip_dicts_with_non_string_keys():
    result = zip_dicts(
        {1: "one", (2, 3): "tuple"},
        {1: "uno", "x": "ex"},
    )

    assert result == {
        1: ["one", "uno"],
        (2, 3): ["tuple", None],
        "x": [None, "ex"],
    }


def test_zip_dicts_with_falsey_values():
    result = zip_dicts(
        {"a": 0, "b": False, "c": ""},
        {"a": None, "b": True},
    )

    assert result == {
        "a": [0, None],
        "b": [False, True],
        "c": ["", None],
    }


def test_zip_dicts_raises_type_error_for_none_argument():
    with pytest.raises(TypeError):
        zip_dicts({"a": 1}, None)


def test_zip_dicts_raises_attribute_error_for_non_mapping_argument():
    with pytest.raises(AttributeError):
        zip_dicts({"a": 1}, ["a"])


def test_zip_dicts_raises_type_error_for_unhashable_keys_from_iterable_argument():
    with pytest.raises(TypeError):
        zip_dicts({"a": 1}, [["a"]])
